onClick:
{{
(() => {

    // ==========================
    // VALIDAR NC
    // ==========================

    if (!qryANCFBuscarNC.data?.length) {

        showAlert(
            "Debe seleccionar una Nota de Crédito válida.",
            "warning"
        );

        return;

    }

    // ==========================
    // VALIDAR FACTURA
    // ==========================

    if (!qryANCFBuscarFC.data?.length) {

        showAlert(
            "Debe seleccionar una Factura válida.",
            "warning"
        );

        return;

    }

    // ==========================
    // VALIDAR MONTO
    // ==========================

    if (
        Number((inpMontoAplicar_ANCF.text || "0").replace(/,/g,"")) <= 0
    ) {

        showAlert(
            "Debe indicar un monto mayor que cero.",
            "warning"
        );

        return;

    }

    // ==========================
    // APLICAR
    // ==========================

    qryANCFAplicar.run()

    .then(() => {

        showAlert(
            "Nota de Crédito aplicada correctamente.",
            "success"
        );

        return Promise.all([

            inpID_NC_ANCF.setValue(""),

            inpID_FC_ANCF.setValue(""),

            inpMontoAplicar_ANCF.setValue("")

        ]);

    })

    .then(() => {

        qryANCFBuscarNC.run();

        qryANCFBuscarFC.run();

    })

    .catch((e) => {

        showAlert(
            e.message,
            "error"
        );

    });

})();
}}
